use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::AppState;

pub fn render_sessions(f: &mut Frame, state: &AppState, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let lines: Vec<Line> = state
        .tabs
        .iter()
        .enumerate()
        .map(|(i, tab)| {
            let selected = i == state.active_tab;
            let style = if selected {
                Style::default()
                    .fg(Color::Cyan)
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(Color::White)
            };
            let prefix = if selected { "● " } else { "  " };
            Line::from(Span::styled(format!("{}{}", prefix, tab.name), style))
        })
        .collect();

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}
```

### Create `rust/crates/app/src/ui/git_panel.rs`

```rust
use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::AppState;

pub fn render_git(f: &mut Frame, state: &AppState, area: Rect) {
    let git = &state.git;
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray))
        .title(Span::styled(
            format!(" {} ", git.branch),
            Style::default().fg(Color::Magenta),
        ));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let mut lines: Vec<Line> = Vec::new();

    // Staged section
    let staged_header = if git.staged_collapsed {
        "▶ Staged"
    } else {
        "▼ Staged"
    };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", staged_header, git.staged.len()),
        Style::default()
            .fg(Color::Green)
            .add_modifier(Modifier::BOLD),
    )));

    if !git.staged_collapsed {
        for (i, file) in git.staged.iter().enumerate() {
            let selected = state
                .git
                .selected
                .as_ref()
                .map(|s| s.staged && s.index == i)
                .unwrap_or(false);
            let status_color = match file.status {
                'A' => Color::Green,
                'D' => Color::Red,
                _ => Color::Yellow,
            };
            let bg = if selected {
                Color::DarkGray
            } else {
                Color::Reset
            };
            lines.push(Line::from(vec![
                Span::styled(
                    format!("  {} ", file.status),
                    Style::default().fg(status_color).bg(bg),
                ),
                Span::styled(file.path.clone(), Style::default().fg(Color::White).bg(bg)),
            ]));
            if selected {
                lines.push(Line::from(vec![
                    Span::raw("     "),
                    Span::styled(
                        " o ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                    Span::styled("|", Style::default().fg(Color::DarkGray)),
                    Span::styled(
                        " u ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                ]));
            }
        }
    }

    lines.push(Line::default());

    // Unstaged section
    let unstaged_header = if git.unstaged_collapsed {
        "▶ Changes"
    } else {
        "▼ Changes"
    };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", unstaged_header, git.unstaged.len()),
        Style::default()
            .fg(Color::Yellow)
            .add_modifier(Modifier::BOLD),
    )));

    if !git.unstaged_collapsed {
        for (i, file) in git.unstaged.iter().enumerate() {
            let selected = state
                .git
                .selected
                .as_ref()
                .map(|s| !s.staged && s.index == i)
                .unwrap_or(false);
            let status_color = match file.status {
                'A' | '?' => Color::Green,
                'D' => Color::Red,
                _ => Color::Yellow,
            };
            let bg = if selected {
                Color::DarkGray
            } else {
                Color::Reset
            };
            lines.push(Line::from(vec![
                Span::styled(
                    format!("  {} ", file.status),
                    Style::default().fg(status_color).bg(bg),
                ),
                Span::styled(file.path.clone(), Style::default().fg(Color::White).bg(bg)),
            ]));
            if selected {
                lines.push(Line::from(vec![
                    Span::raw("     "),
                    Span::styled(
                        " o ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                    Span::styled("|", Style::default().fg(Color::DarkGray)),
                    Span::styled(
                        " s ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                    Span::styled("|", Style::default().fg(Color::DarkGray)),
                    Span::styled(
                        " d ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                ]));
            }
        }
    }

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}
