### Create `rust/crates/app/src/ui/files.rs`

```rust
use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::{AppState, FileNode};

fn file_icon(node: &FileNode) -> &'static str {
    if node.is_dir {
        if node.expanded { "📂" } else { "📁" }
    } else {
        match node.extension.as_str() {
            "ts" | "tsx" => "TS",
            "js" | "jsx" => "JS",
            "json" => "{}",
            "md" => "MD",
            "rs" => "RS",
            "toml" => "TM",
            "yaml" | "yml" => "YM",
            _ => "  ",
        }
    }
}

fn file_icon_color(node: &FileNode) -> Color {
    if node.is_dir {
        Color::Blue
    } else {
        match node.extension.as_str() {
            "ts" | "tsx" => Color::Cyan,
            "js" | "jsx" => Color::Yellow,
            "json" => Color::Green,
            "md" => Color::White,
            "rs" => Color::Red,
            _ => Color::Gray,
        }
    }
}

pub fn render_files(f: &mut Frame, state: &AppState, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let files = &state.files;
    let visible_height = inner.height as usize;
    let start = files.scroll;
    let end = (start + visible_height).min(files.nodes.len());

    if files.nodes.is_empty() {
        let hint = Paragraph::new("(empty)").style(Style::default().fg(Color::DarkGray));
        f.render_widget(hint, inner);
        return;
    }

    let lines: Vec<Line> = files.nodes[start..end]
        .iter()
        .enumerate()
        .map(|(i, node)| {
            let abs_i = start + i;
            let selected = abs_i == files.selected;
            let indent = "  ".repeat(node.depth);
            let pin_indicator = if node.pinned {
                Span::styled("* ", Style::default().fg(Color::Cyan))
            } else if selected {
                Span::styled("+ ", Style::default().fg(Color::DarkGray))
            } else {
                Span::raw("  ")
            };
            let icon_style = Style::default().fg(file_icon_color(node));
            let name_style = if selected {
                Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(Color::White)
            };
            Line::from(vec![
                Span::raw(indent),
                pin_indicator,
                Span::styled(format!("{} ", file_icon(node)), icon_style),
                Span::styled(node.name.clone(), name_style),
            ])
        })
        .collect();

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}
