50	async fn run_loop(
51	    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
52	    state: &mut AppState,
53	) -> Result<()> {
54	    let settings = clui_config::Settings::from_env();
55	    let (event_tx, mut event_rx) = mpsc::channel::<AppEvent>(256);
56	
57	    // Spawn agent for initial tab if API key available
58	    if let Some(api_key) = &settings.anthropic_api_key {
59	        let config = clui_agent::AgentConfig {
60	            api_key: api_key.clone(),
61	            model: settings.default_model.clone(),
62	            max_tokens: 8192,
63	            cwd: state.cwd.to_string_lossy().to_string(),
64	        };
65	        let tx = agent_task::spawn_agent(state.tabs[0].id.clone(), config, event_tx.clone());
66	        if let TabKind::Chat { agent_tx } = &mut state.tabs[0].kind {
67	            *agent_tx = Some(tx);
68	        }
69	    }
70	
71	    // Initial git refresh
72	    let _ = event_tx.send(AppEvent::GitRefresh).await;
73	
74	    // Spawn git watcher
75	    let etx_git = event_tx.clone();
76	    tokio::spawn(async move {
77	        loop {
78	            tokio::time::sleep(Duration::from_secs(5)).await;
79	            let _ = etx_git.send(AppEvent::GitRefresh).await;
80	        }
81	    });
82	
83	    loop {
84	        terminal.draw(|f| ui::render(f, state))?;
85	
86	        // Drain async events
87	        while let Ok(evt) = event_rx.try_recv() {
88	            router::handle(state, evt);
89	        }
90	
91	        if crossterm_poll(Duration::from_millis(16))? {
92	            match crossterm_read()? {
93	                Event::Key(k) => router::handle(
94	                    state,
95	                    AppEvent::Key {
96	                        code: k.code,
97	                        modifiers: k.modifiers,
98	                    },
99	                ),
100	                Event::Mouse(m) => router::handle(
101	                    state,
102	                    AppEvent::Mouse {
103	                        kind: m.kind,
104	                        col: m.column,
105	                        row: m.row,
106	                        modifiers: m.modifiers,
107	                    },
108	                ),
109	                Event::Resize(c, r) => {
110	                    router::handle(state, AppEvent::Resize { cols: c, rows: r })
111	                }
112	                _ => {}
113	            }
114	        } else {
115	            router::handle(state, AppEvent::Tick);
116	        }
117	
118	        // Dispatch pending prompts to agent
119	        if let Some(tab) = state.active_tab_mut() {
120	            if let Some(prompt) = tab.pending_prompt.take() {
121	                if let TabKind::Chat {
122	                    agent_tx: Some(tx),
123	                } = &tab.kind
124	                {
125	                    let _ = tx
126	                        .send(agent_task::AgentCommand::SendPrompt { text: prompt })
127	                        .await;
128	                }
129	            }
130	        }
131	
132	        if state.should_quit {
133	            break;
134	        }
135	    }
136	    Ok(())
137	}
