4	
5	#[derive(Debug, Clone, PartialEq)]
6	pub enum FileStatus { Modified, Added, Deleted, Renamed, Untracked }
7	
8	#[derive(Debug, Clone)]
9	pub struct DiffEntry {
10	    pub path: String,
11	    pub status: FileStatus,
12	    pub staged: bool,
13	}
14	
15	impl DiffEntry {
16	    pub fn status_char(&self) -> char {
17	        match self.status {
18	            FileStatus::Modified => 'M',
19	            FileStatus::Added => 'A',
20	            FileStatus::Deleted => 'D',
21	            FileStatus::Renamed => 'R',
22	            FileStatus::Untracked => '?',
23	        }
24	    }
25	}
26	
27	#[derive(Debug, Clone, Default)]
28	pub struct GitStatusResult {
29	    pub branch: String,
30	    pub staged: Vec<DiffEntry>,
31	    pub unstaged: Vec<DiffEntry>,
32	}
33	
34	pub fn git_status(cwd: &Path) -> Result<GitStatusResult> {
35	    let repo = Repository::discover(cwd)
36	        .context("not a git repository")?;
37	
38	    let branch = repo.head()
39	        .ok()
40	        .and_then(|h| h.shorthand().map(|s| s.to_string()))
41	        .unwrap_or_else(|| "HEAD".to_string());
42	
43	    let mut opts = StatusOptions::new();
44	    opts.include_untracked(true).recurse_untracked_dirs(true);
45	    let statuses = repo.statuses(Some(&mut opts))?;
46	
47	    let mut staged = Vec::new();
48	    let mut unstaged = Vec::new();
49	
50	    for entry in statuses.iter() {
51	        let path = entry.path().unwrap_or("").to_string();
52	        let s = entry.status();
53	
54	        if s.contains(git2::Status::INDEX_MODIFIED) || s.contains(git2::Status::INDEX_NEW) || s.contains(git2::Status::INDEX_DELETED) {
55	            let status = if s.contains(git2::Status::INDEX_NEW) { FileStatus::Added }
56	                else if s.contains(git2::Status::INDEX_DELETED) { FileStatus::Deleted }
57	                else { FileStatus::Modified };
58	            staged.push(DiffEntry { path: path.clone(), status, staged: true });
59	        }
60	
61	        if s.contains(git2::Status::WT_MODIFIED) || s.contains(git2::Status::WT_DELETED) {
62	            let status = if s.contains(git2::Status::WT_DELETED) { FileStatus::Deleted }
63	                else { FileStatus::Modified };
64	            unstaged.push(DiffEntry { path: path.clone(), status, staged: false });
65	        }
66	
67	        if s.contains(git2::Status::WT_NEW) {
68	            unstaged.push(DiffEntry { path, status: FileStatus::Untracked, staged: false });
69	        }
70	    }
71	
72	    Ok(GitStatusResult { branch, staged, unstaged })
73	}
