75	pub fn stage_file(cwd: &Path, path: &str) -> Result<()> {
76	    let repo = Repository::discover(cwd)?;
77	    let mut index = repo.index()?;
78	    index.add_path(Path::new(path))?;
79	    index.write()?;
80	    Ok(())
81	}
82	
83	pub fn unstage_file(cwd: &Path, path: &str) -> Result<()> {
84	    let repo = Repository::discover(cwd)?;
85	    let head = repo.head().ok().and_then(|h| h.peel_to_commit().ok());
86	    match head {
87	        Some(_) => {
88	            let head_obj = repo.revparse_single("HEAD")?;
89	            repo.reset_default(Some(&head_obj), &[Path::new(path)])?;
90	        }
91	        None => {
92	            let mut index = repo.index()?;
93	            index.remove_path(Path::new(path))?;
94	            index.write()?;
95	        }
96	    }
97	    Ok(())
98	}
99	
100	pub fn discard_file(cwd: &Path, path: &str) -> Result<()> {
101	    let repo = Repository::discover(cwd)?;
102	    let mut checkout = git2::build::CheckoutBuilder::new();
103	    checkout.path(path).force();
104	    repo.checkout_head(Some(&mut checkout))?;
105	    Ok(())
106	}
107	
108	pub fn file_diff(cwd: &Path, path: &str, staged: bool) -> Result<String> {
109	    let repo = Repository::discover(cwd)?;
110	    let mut diff_opts = git2::DiffOptions::new();
111	    diff_opts.pathspec(path);
112	
113	    let diff = if staged {
114	        let head_tree = repo.head().ok()
115	            .and_then(|h| h.peel_to_commit().ok())
116	            .and_then(|c| c.tree().ok());
117	        let index = repo.index()?;
118	        repo.diff_tree_to_index(head_tree.as_ref(), Some(&index), Some(&mut diff_opts))?
119	    } else {
120	        repo.diff_index_to_workdir(None, Some(&mut diff_opts))?
121	    };
122	
123	    let mut output = String::new();
124	    diff.print(git2::DiffFormat::Patch, |_, _, line| {
125	        let content = std::str::from_utf8(line.content()).unwrap_or("");
126	        output.push_str(content);
127	        true
128	    })?;
129	    Ok(output)
130	}
