18	pub fn discover_in_dir(dir: &Path) -> Vec<Skill> {
19	    let Ok(entries) = std::fs::read_dir(dir) else { return Vec::new() };
20	    let mut skills: Vec<Skill> = entries
21	        .filter_map(|e| e.ok())
22	        .filter(|e| e.path().extension().and_then(|s| s.to_str()) == Some("md"))
23	        .map(|e| {
24	            let path = e.path();
