33	pub fn apply_override_flags(higher: &[Skill], lower: &[Skill]) -> Vec<Skill> {
34	    let higher_names: std::collections::HashSet<&str> =
35	        higher.iter().map(|s| s.name.as_str()).collect();
36	    lower.iter().map(|s| Skill {
37	        overridden: higher_names.contains(s.name.as_str()),
38	        ..s.clone()
39	    }).collect()
40	}
