use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::AppState;

pub fn render_sessions(f: &mut Frame, state: &AppState, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let lines: Vec<Line> = state
        .tabs
        .iter()
        .enumerate()
        .map(|(i, tab)| {
            let selected = i == state.active_tab;
            let style = if selected {
                Style::default()
                    .fg(Color::Cyan)
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(Color::White)
            };
            let prefix = if selected { "● " } else { "  " };
            Line::from(Span::styled(format!("{}{}", prefix, tab.name), style))
        })
        .collect();

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::AppState;

pub fn render_git(f: &mut Frame, state: &AppState, area: Rect) {
    let git = &state.git;
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray))
        .title(Span::styled(
            format!(" {} ", git.branch),
            Style::default().fg(Color::Magenta),
        ));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let mut lines: Vec<Line> = Vec::new();

    // Staged section
    let staged_header = if git.staged_collapsed {
        "▶ Staged"
    } else {
        "▼ Staged"
    };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", staged_header, git.staged.len()),
        Style::default()
            .fg(Color::Green)
            .add_modifier(Modifier::BOLD),
    )));

    if !git.staged_collapsed {
        for (i, file) in git.staged.iter().enumerate() {
            let selected = state
                .git
                .selected
                .as_ref()
                .map(|s| s.staged && s.index == i)
                .unwrap_or(false);
            let status_color = match file.status {
                'A' => Color::Green,
                'D' => Color::Red,
                _ => Color::Yellow,
            };
            let bg = if selected {
                Color::DarkGray
            } else {
                Color::Reset
            };
            lines.push(Line::from(vec![
                Span::styled(
                    format!("  {} ", file.status),
                    Style::default().fg(status_color).bg(bg),
                ),
                Span::styled(file.path.clone(), Style::default().fg(Color::White).bg(bg)),
            ]));
            if selected {
                lines.push(Line::from(vec![
                    Span::raw("     "),
                    Span::styled(
                        " o ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                    Span::styled("|", Style::default().fg(Color::DarkGray)),
                    Span::styled(
                        " u ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                ]));
            }
        }
    }

    lines.push(Line::default());

    // Unstaged section
    let unstaged_header = if git.unstaged_collapsed {
        "▶ Changes"
    } else {
        "▼ Changes"
    };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", unstaged_header, git.unstaged.len()),
        Style::default()
            .fg(Color::Yellow)
            .add_modifier(Modifier::BOLD),
    )));

    if !git.unstaged_collapsed {
        for (i, file) in git.unstaged.iter().enumerate() {
            let selected = state
                .git
                .selected
                .as_ref()
                .map(|s| !s.staged && s.index == i)
                .unwrap_or(false);
            let status_color = match file.status {
                'A' | '?' => Color::Green,
                'D' => Color::Red,
                _ => Color::Yellow,
            };
            let bg = if selected {
                Color::DarkGray
            } else {
                Color::Reset
            };
            lines.push(Line::from(vec![
                Span::styled(
                    format!("  {} ", file.status),
                    Style::default().fg(status_color).bg(bg),
                ),
                Span::styled(file.path.clone(), Style::default().fg(Color::White).bg(bg)),
            ]));
            if selected {
                lines.push(Line::from(vec![
                    Span::raw("     "),
                    Span::styled(
                        " o ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                    Span::styled("|", Style::default().fg(Color::DarkGray)),
                    Span::styled(
                        " s ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                    Span::styled("|", Style::default().fg(Color::DarkGray)),
                    Span::styled(
                        " d ",
                        Style::default().fg(Color::Black).bg(Color::White),
                    ),
                ]));
            }
        }
    }

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::{AppState, FileNode};

fn file_icon(node: &FileNode) -> &'static str {
    if node.is_dir {
        if node.expanded { "📂" } else { "📁" }
    } else {
        match node.extension.as_str() {
            "ts" | "tsx" => "TS",
            "js" | "jsx" => "JS",
            "json" => "{}",
            "md" => "MD",
            "rs" => "RS",
            "toml" => "TM",
            "yaml" | "yml" => "YM",
            _ => "  ",
        }
    }
}

fn file_icon_color(node: &FileNode) -> Color {
    if node.is_dir {
        Color::Blue
    } else {
        match node.extension.as_str() {
            "ts" | "tsx" => Color::Cyan,
            "js" | "jsx" => Color::Yellow,
            "json" => Color::Green,
            "md" => Color::White,
            "rs" => Color::Red,
            _ => Color::Gray,
        }
    }
}

pub fn render_files(f: &mut Frame, state: &AppState, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let files = &state.files;
    let visible_height = inner.height as usize;
    let start = files.scroll;
    let end = (start + visible_height).min(files.nodes.len());

    if files.nodes.is_empty() {
        let hint = Paragraph::new("(empty)").style(Style::default().fg(Color::DarkGray));
        f.render_widget(hint, inner);
        return;
    }

    let lines: Vec<Line> = files.nodes[start..end]
        .iter()
        .enumerate()
        .map(|(i, node)| {
            let abs_i = start + i;
            let selected = abs_i == files.selected;
            let indent = "  ".repeat(node.depth);
            let pin_indicator = if node.pinned {
                Span::styled("* ", Style::default().fg(Color::Cyan))
            } else if selected {
                Span::styled("+ ", Style::default().fg(Color::DarkGray))
            } else {
                Span::raw("  ")
            };
            let icon_style = Style::default().fg(file_icon_color(node));
            let name_style = if selected {
                Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(Color::White)
            };
            Line::from(vec![
                Span::raw(indent),
                pin_indicator,
                Span::styled(format!("{} ", file_icon(node)), icon_style),
                Span::styled(node.name.clone(), name_style),
            ])
        })
        .collect();

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

use ratatui::{
    layout::{Alignment, Constraint, Layout, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::{AppState, LeftPanel};

pub fn render_left_sidebar(f: &mut Frame, state: &AppState, area: Rect) {
    let layout =
        Layout::vertical([Constraint::Length(3), Constraint::Min(0)]).split(area);
    let tab_area = layout[0];
    let content_area = layout[1];

    let tab_cols = Layout::horizontal([
        Constraint::Ratio(1, 3),
        Constraint::Ratio(1, 3),
        Constraint::Ratio(1, 3),
    ])
    .split(tab_area);

    let panels = [LeftPanel::Sessions, LeftPanel::Git, LeftPanel::Files];
    let labels = ["Sessions", "Git", "Files"];

    for (i, (panel, label)) in panels.iter().zip(labels.iter()).enumerate() {
        let active = &state.layout.left_panel == panel;
        let border_style = if active {
            Style::default().fg(Color::Cyan)
        } else {
            Style::default().fg(Color::DarkGray)
        };
        let text_style = if active {
            Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(Color::Gray)
        };
        let block = Block::default()
            .borders(Borders::ALL)
            .border_type(if active {
                BorderType::Rounded
            } else {
                BorderType::Plain
            })
            .border_style(border_style);
        let para = Paragraph::new(Line::from(Span::styled(*label, text_style)))
            .block(block)
            .alignment(Alignment::Center);
        f.render_widget(para, tab_cols[i]);
    }

    match state.layout.left_panel {
        LeftPanel::Sessions => super::sessions::render_sessions(f, state, content_area),
        LeftPanel::Git => super::git_panel::render_git(f, state, content_area),
        LeftPanel::Files => super::files::render_files(f, state, content_area),
    }
}

use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};
use crate::state::{AppState, SkillEntry};

pub fn render_skills(f: &mut Frame, state: &AppState, area: Rect) {
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray))
        .title(" Skills ");
    let inner = block.inner(area);
    f.render_widget(block, area);

    let mut lines: Vec<Line> = Vec::new();
    let skills = &state.skills;

    let repo_header = if skills.repo_collapsed { "▶ Repo" } else { "▼ Repo" };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", repo_header, skills.repo.len()),
        Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD),
    )));
    if !skills.repo_collapsed {
        for s in &skills.repo {
            lines.push(skill_line(s));
        }
    }

    let user_header = if skills.user_collapsed { "▶ User" } else { "▼ User" };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", user_header, skills.user.len()),
        Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD),
    )));
    if !skills.user_collapsed {
        for s in &skills.user {
            lines.push(skill_line(s));
        }
    }

    let global_header = if skills.global_collapsed {
        "▶ Global"
    } else {
        "▼ Global"
    };
    lines.push(Line::from(Span::styled(
        format!(" {} ({}) ", global_header, skills.global.len()),
        Style::default()
            .fg(Color::DarkGray)
            .add_modifier(Modifier::BOLD),
    )));
    if !skills.global_collapsed {
        for s in &skills.global {
            lines.push(skill_line(s));
        }
    }

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

fn skill_line(s: &SkillEntry) -> Line<'static> {
    let style = if s.overridden {
        Style::default().fg(Color::DarkGray)
    } else {
        Style::default().fg(Color::White)
    };
    Line::from(Span::styled(format!("  /{}", s.name), style))
}

