use ratatui::{
    layout::Rect,
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};

pub fn render_file_viewer(
    f: &mut Frame,
    path: &str,
    content: &str,
    scroll: usize,
    area: Rect,
) {
    let filename = std::path::Path::new(path)
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or(path);
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray))
        .title(Span::styled(
            format!(" {} ", filename),
            Style::default().fg(Color::Cyan),
        ));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let total = content.lines().count();
    let num_width = if total == 0 { 1 } else { total.to_string().len() };

    let lines: Vec<Line> = content
        .lines()
        .enumerate()
        .skip(scroll)
        .take(inner.height as usize)
        .map(|(i, line)| {
            Line::from(vec![
                Span::styled(
                    format!("{:>width$} ", i + 1, width = num_width),
                    Style::default().fg(Color::DarkGray),
                ),
                Span::styled(line.to_string(), Style::default().fg(Color::White)),
            ])
        })
        .collect();

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

use ratatui::{
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};

pub fn render_diff_viewer(
    f: &mut Frame,
    path: &str,
    diff: &str,
    staged: bool,
    scroll: usize,
    area: Rect,
) {
    let staged_label = if staged { "staged" } else { "unstaged" };
    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(Style::default().fg(Color::DarkGray))
        .title(Span::styled(
            format!(" {} [{}] ", path, staged_label),
            Style::default().fg(Color::Cyan),
        ));
    let inner = block.inner(area);
    f.render_widget(block, area);

    let lines: Vec<Line> = diff
        .lines()
        .skip(scroll)
        .take(inner.height as usize)
        .map(|line| {
            if line.starts_with('+') && !line.starts_with("+++") {
                Line::from(Span::styled(
                    line.to_string(),
                    Style::default().fg(Color::Green),
                ))
            } else if line.starts_with('-') && !line.starts_with("---") {
                Line::from(Span::styled(
                    line.to_string(),
                    Style::default().fg(Color::Red),
                ))
            } else if line.starts_with("@@") {
                Line::from(Span::styled(
                    line.to_string(),
                    Style::default()
                        .fg(Color::Cyan)
                        .add_modifier(Modifier::BOLD),
                ))
            } else if line.starts_with("diff ")
                || line.starts_with("index ")
                || line.starts_with("---")
                || line.starts_with("+++")
            {
                Line::from(Span::styled(
                    line.to_string(),
                    Style::default().fg(Color::DarkGray),
                ))
            } else {
                Line::from(Span::styled(
                    line.to_string(),
                    Style::default().fg(Color::Gray),
                ))
            }
        })
        .collect();

    let para = Paragraph::new(lines);
    f.render_widget(para, inner);
}

use crate::state::FileNode;
use std::path::Path;

const IGNORE: &[&str] = &[
    "node_modules",
    ".git",
    "dist",
    "coverage",
    "target",
    ".next",
    "build",
    "__pycache__",
];

pub fn load_children(parent: &Path, depth: usize) -> Vec<FileNode> {
    let Ok(entries) = std::fs::read_dir(parent) else {
        return Vec::new();
    };
    let mut nodes: Vec<FileNode> = entries
        .filter_map(|e| e.ok())
        .filter(|e| {
            let name = e.file_name();
            let name_str = name.to_string_lossy();
            !name_str.starts_with('.') || name_str == ".claude"
        })
        .filter(|e| {
            let name = e.file_name().to_string_lossy().to_string();
            !IGNORE.contains(&name.as_str())
        })
        .map(|e| {
            let path = e.path();
            let is_dir = path.is_dir();
            let name = e.file_name().to_string_lossy().to_string();
            let ext = path
                .extension()
                .and_then(|s| s.to_str())
                .unwrap_or("")
                .to_string();
            FileNode {
                name,
                path: path.to_string_lossy().to_string(),
                depth,
                is_dir,
                expanded: false,
                pinned: false,
                extension: ext,
            }
        })
        .collect();
    nodes.sort_by(|a, b| b.is_dir.cmp(&a.is_dir).then(a.name.cmp(&b.name)));
    nodes
}

