use crate::state::{AppState, TabKind};

pub fn render(f: &mut Frame, state: &AppState) {
    let area = f.area();
    let cols = layout::compute_columns(&state.layout, area);

    layout::render_tab_bar(f, state, cols.tab_bar);

    if state.layout.left_visible {
        sidebar_left::render_left_sidebar(f, state, cols.left);
    }

    let center_layout = ratatui::layout::Layout::vertical([
        Constraint::Length(3),
        Constraint::Min(3),
        Constraint::Length(3),
        Constraint::Min(5),
    ])
    .split(cols.center);

    let focused = matches!(state.layout.focus, crate::state::Focus::Input);

    if let Some(tab) = state.active_tab() {
        match &tab.kind {
            TabKind::Chat { .. } => {
                info_bar::render_info_bar(f, Some(tab), center_layout[0]);
                chat::render_chat(f, tab, center_layout[1]);
                context_bar::render_context_bar(f, Some(tab), center_layout[2]);
                input::render_input(f, &tab.input, center_layout[3], focused);
            }
            TabKind::FileViewer {
                path,
                content,
                scroll,
                ..
            } => {
                file_viewer::render_file_viewer(f, path, content, *scroll, cols.center);
            }
            TabKind::DiffViewer {
                path,
                diff,
                staged,
                scroll,
            } => {
                diff_viewer::render_diff_viewer(f, path, diff, *staged, *scroll, cols.center);
            }
        }
    } else {
        // No active tab — just render placeholders
        let block = Block::default()
            .borders(Borders::ALL)
            .border_type(BorderType::Rounded)
            .border_style(Style::default().fg(Color::DarkGray));
        f.render_widget(block, cols.center);
    }

    if state.layout.right_visible {
        sidebar_right::render_right_sidebar(f, state, cols.right);
    }
}

