// Load initial file tree
let initial_nodes = filetree::load_children(&app.cwd, 0);
app.files.nodes = initial_nodes;

// Load skills
let paths = clui_config::Paths::new();
let skill_set = clui_skills::discover(&app.cwd, &paths);
app.skills.repo = skill_set.repo.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
app.skills.user = skill_set.user.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
app.skills.global = skill_set.global.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();

let result = run_loop(&mut terminal, &mut app).await;

// Git navigation: Up/Down when left sidebar git panel active
AppEvent::Key { code: KeyCode::Up, .. }
    if state.layout.left_panel == crate::state::LeftPanel::Git
        && !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    match &state.git.selected {
        None => {
            let total = state.git.staged.len() + state.git.unstaged.len();
            if total > 0 {
                state.git.selected = Some(crate::state::GitSelection {
                    index: 0,
                    staged: !state.git.staged.is_empty(),
                });
            }
        }
        Some(sel) => {
            if sel.index > 0 {
                let new_sel = crate::state::GitSelection {
                    index: sel.index - 1,
                    staged: sel.staged,
                };
                state.git.selected = Some(new_sel);
            } else if sel.staged && !state.git.unstaged.is_empty() {
                state.git.selected = Some(crate::state::GitSelection {
                    index: 0,
                    staged: false,
                });
            }
        }
    }
}
AppEvent::Key { code: KeyCode::Down, .. }
    if state.layout.left_panel == crate::state::LeftPanel::Git
        && !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    match &state.git.selected {
        None => {
            let total = state.git.staged.len() + state.git.unstaged.len();
            if total > 0 {
                state.git.selected = Some(crate::state::GitSelection {
                    index: 0,
                    staged: !state.git.staged.is_empty(),
                });
            }
        }
        Some(sel) => {
            let max = if sel.staged {
                state.git.staged.len()
            } else {
                state.git.unstaged.len()
            };
            if sel.index + 1 < max {
                let new_sel = crate::state::GitSelection {
                    index: sel.index + 1,
                    staged: sel.staged,
                };
                state.git.selected = Some(new_sel);
            } else if sel.staged {
                state.git.selected = Some(crate::state::GitSelection {
                    index: 0,
                    staged: false,
                });
            }
        }
    }
}
// Enter on git file → open diff viewer
AppEvent::Key { code: KeyCode::Enter, .. }
    if state.layout.left_panel == crate::state::LeftPanel::Git
        && !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    if let Some(sel) = state.git.selected.clone() {
        let (path_opt, staged) = if sel.staged {
            (state.git.staged.get(sel.index).map(|f| f.path.clone()), true)
        } else {
            (state.git.unstaged.get(sel.index).map(|f| f.path.clone()), false)
        };
        if let Some(path) = path_opt {
            let diff = clui_git::file_diff(&state.cwd, &path, staged).unwrap_or_default();
            let id = format!("diff-{}-{}", if staged { "staged" } else { "unstaged" }, path);
            let name = format!(
                "diff:{}",
                std::path::Path::new(&path)
                    .file_name()
                    .and_then(|n| n.to_str())
                    .unwrap_or(&path)
            );
            if !state.tabs.iter().any(|t| t.id == id) {
                let mut tab = crate::state::TabState::new_chat(&id, &name);
                tab.kind = crate::state::TabKind::DiffViewer { path, diff, staged, scroll: 0 };
                state.tabs.push(tab);
            }
            state.active_tab = state
                .tabs
                .iter()
                .position(|t| t.id == id)
                .unwrap_or(state.active_tab);
        }
    }
}
// Alt+s stage (git)
AppEvent::Key { code: KeyCode::Char('s'), modifiers }
    if modifiers.contains(KeyModifiers::ALT)
        && state.layout.left_panel == crate::state::LeftPanel::Git =>
{
    if let Some(sel) = state.git.selected.clone() {
        if !sel.staged {
            if let Some(file) = state.git.unstaged.get(sel.index) {
                let path = file.path.clone();
                let _ = clui_git::stage_file(&state.cwd, &path);
            }
        }
    }
}
// Alt+u unstage (git)
AppEvent::Key { code: KeyCode::Char('u'), modifiers }
    if modifiers.contains(KeyModifiers::ALT)
        && state.layout.left_panel == crate::state::LeftPanel::Git =>
{
    if let Some(sel) = state.git.selected.clone() {
        if sel.staged {
            if let Some(file) = state.git.staged.get(sel.index) {
                let path = file.path.clone();
                let _ = clui_git::unstage_file(&state.cwd, &path);
            }
        }
    }
}
// Alt+d discard (git)
AppEvent::Key { code: KeyCode::Char('d'), modifiers }
    if modifiers.contains(KeyModifiers::ALT)
        && state.layout.left_panel == crate::state::LeftPanel::Git =>
{
    if let Some(sel) = state.git.selected.clone() {
        if !sel.staged {
            if let Some(file) = state.git.unstaged.get(sel.index) {
                let path = file.path.clone();
                state.confirm_dialog = Some(crate::state::ConfirmDialog {
                    message: format!("Discard changes to {}?", path),
                    action: crate::state::ConfirmAction::DiscardFile { path },
                });
            }
        }
    }
}
// Files panel: Up/Down navigation
AppEvent::Key { code: KeyCode::Up, .. }
    if state.layout.left_panel == crate::state::LeftPanel::Files
        && !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    if state.files.selected > 0 {
        state.files.selected -= 1;
        if state.files.selected < state.files.scroll {
            state.files.scroll = state.files.selected;
        }
    }
}
AppEvent::Key { code: KeyCode::Down, .. }
    if state.layout.left_panel == crate::state::LeftPanel::Files
        && !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    if state.files.selected + 1 < state.files.nodes.len() {
        state.files.selected += 1;
    }
}
// Files panel: Enter to expand dir or open file
AppEvent::Key { code: KeyCode::Enter, .. }
    if state.layout.left_panel == crate::state::LeftPanel::Files
        && !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    let idx = state.files.selected;
    if let Some(node) = state.files.nodes.get(idx) {
        if node.is_dir {
            let expanded = !node.expanded;
            let depth = node.depth;
            let path = node.path.clone();
            state.files.nodes[idx].expanded = expanded;
            if expanded {
                let children = crate::filetree::load_children(
                    std::path::Path::new(&path),
                    depth + 1,
                );
                state.files.nodes.splice(idx + 1..idx + 1, children);
            } else {
                let mut end = idx + 1;
                while end < state.files.nodes.len()
                    && state.files.nodes[end].depth > depth
                {
                    end += 1;
                }
                state.files.nodes.drain(idx + 1..end);
            }
        } else {
            let path = node.path.clone();
            let name = node.name.clone();
            let ext = node.extension.clone();
            if let Ok(content) = std::fs::read_to_string(&path) {
                let id = format!("file-{}", path);
                if !state.tabs.iter().any(|t| t.id == id) {
                    let mut tab = crate::state::TabState::new_chat(&id, &name);
                    tab.kind = crate::state::TabKind::FileViewer {
                        path: path.clone(),
                        content,
                        language: ext,
                        scroll: 0,
                    };
                    state.tabs.push(tab);
                }
                state.active_tab = state
                    .tabs
                    .iter()
                    .position(|t| t.id == id)
                    .unwrap_or(state.active_tab);
            }
        }
    }
}
// Alt+P: pin/unpin file
AppEvent::Key { code: KeyCode::Char('p'), modifiers }
    if modifiers.contains(KeyModifiers::ALT) =>
{
    let idx = state.files.selected;
    if let Some(node) = state.files.nodes.get_mut(idx) {
        node.pinned = !node.pinned;
        let pinned = node.pinned;
        let is_dir = node.is_dir;
        let path = node.path.clone();
        let name = node.name.clone();
        if pinned {
            if let Some(tab) = state.active_tab_mut() {
                tab.pins.push(crate::state::Pin {
                    kind: if is_dir {
                        crate::state::PinKind::Dir
                    } else {
                        crate::state::PinKind::File
                    },
                    path,
                    display: name,
                    sticky: true,
                });
            }
        }
    }
}
// File/Diff viewer scroll (only when focus is not Input)
AppEvent::Key { code: KeyCode::Up, .. }
    if !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    if let Some(tab) = state.active_tab_mut() {
        match &mut tab.kind {
            crate::state::TabKind::FileViewer { scroll, .. } => {
                *scroll = scroll.saturating_sub(1);
            }
            crate::state::TabKind::DiffViewer { scroll, .. } => {
                *scroll = scroll.saturating_sub(1);
            }
            _ => {}
        }
    }
}
AppEvent::Key { code: KeyCode::Down, .. }
    if !matches!(state.layout.focus, crate::state::Focus::Input) =>
{
    if let Some(tab) = state.active_tab_mut() {
        match &mut tab.kind {
            crate::state::TabKind::FileViewer { scroll, .. } => {
                *scroll += 1;
            }
            crate::state::TabKind::DiffViewer { scroll, .. } => {
                *scroll += 1;
            }
            _ => {}
        }
    }
}
// Skills tier collapse (1/2/3 when right sidebar focused)
AppEvent::Key { code: KeyCode::Char('1'), .. }
    if matches!(state.layout.focus, crate::state::Focus::RightSidebar) =>
{
    state.skills.repo_collapsed = !state.skills.repo_collapsed;
}
AppEvent::Key { code: KeyCode::Char('2'), .. }
    if matches!(state.layout.focus, crate::state::Focus::RightSidebar) =>
{
